// // This module selects between two 8-bit inputs based on the select signal. When S is 0, it outputs B; when S is 1, it outputs A.
module mux2to1 (  
    input [7:0] A,  
    input [7:0] B,  
    input S,  
    output reg [7:0] Y  
);  
    always @(*) begin  
        if (S == 0)  
            Y = A;  
        else  
            Y = B;  
    end  
endmodule
